 16	} from '@patternfly/react-core';
 17	import { useTranslation } from 'react-i18next';
 18	
 19	const DEFAULT_EXPIRATION = 15;
 20	const DEFAULT_CLAIMS = 1;
 21	
 22	enum ValidForUnit {
 23	  Minutes = 'm',
 24	  Hours = 'h'
 25	}
 26	
 27	const options = [
 28	  { value: ValidForUnit.Minutes, label: 'min' },
 29	  { value: ValidForUnit.Hours, label: 'hr' }
 30	];
 31	
 32	export const FormPage: FC<{
 33	  name?: string;
 34	  onSetName(value: string): void;
 35	  onSetValidFor(value: number | undefined): void;
 36	  onSetValidForUnit(value: ValidForUnit): void;
 37	  onSetClaims(value: number | undefined): void;
 38	  onSetCode(value: string): void;
 39	}> = function ({ name, onSetName, onSetValidFor, onSetValidForUnit, onSetClaims, onSetCode }) {
 40	  const { t } = useTranslation(I18nNamespace);
 41	
 42	  const [expiration, setExpiration] = useState<number | string>(DEFAULT_EXPIRATION);
 43	  const [claims, setClaims] = useState<number | string>(DEFAULT_CLAIMS);
 44	  const [timeDimension, setTimeDimension] = useState(options[0].value);
 45	  const [code, setCode] = useState<string>('');
 46	
 47	  const handleSetName = (_: FormEvent, value: string) => {
 48	    onSetName(value);
 49	  };
 50	
 51	  const handleSetClaimExpiration = (value: string) => {
 52	    let numberValue: number | undefined = Number(value);
 53	
 54	    // If the input is not a valid number or less than/equal to 0, set numberValue to 1
 55	    if (isNaN(numberValue) || numberValue <= 0) {
 56	      numberValue = DEFAULT_EXPIRATION;
 57	    }
 58	
 59	    if (!value) {
 60	      numberValue = undefined;
 61	    }
 62	
 63	    setExpiration(numberValue || '');
 64	    onSetValidFor(numberValue);
 65	  };
 66	  const handleSetClaimsMade = (value: string) => {
 67	    let numberValue: number | undefined = Number(value);
 68	
 69	    if (isNaN(numberValue) || numberValue <= 0) {
 70	      numberValue = DEFAULT_CLAIMS;
 71	    }
 72	
 73	    if (!value) {
 74	      numberValue = undefined;
 75	    }
 76	
 77	    setClaims(numberValue || '');
 78	    onSetClaims(numberValue);
 79	  };
 80	
 81	  const onChangeTimeDimension = (value: ValidForUnit) => {
 82	    setTimeDimension(value);
 83	    onSetValidForUnit(value);
 84	  };
 85	
 86	  const handleSetCode = (value: string) => {
 87	    setCode(value);
 88	    onSetCode(value);
 89	  };
 90	
 91	  return (
 92	    <Stack hasGutter>
 93	      <StackItem>
 94	        <Title headingLevel="h1">{t('Configuration')}</Title>
 95	      </StackItem>
 96	
 97	      <StackItem>
 98	        <Form isHorizontal>
 99	          <FormGroup fieldId="filename-input" isRequired label={t('File name')} title=" ">
100	            <TextInput
101	              aria-label="filename input"
102	              isRequired
103	              type="text"
104	              value={name}
105	              onChange={handleSetName}
106	              autoFocus
107	            />
108	          </FormGroup>
109	
110	          <FormGroup
111	            fieldId="redemption-allowed-input"
112	            label={t('Redemptions Allowed')}
113	            labelIcon={<TooltipInfoButton content={t('tooltipRedemptionAllowed')} />}
114	            title=""
115	          >
116	            <TextInput
117	              aria-label="redemption allowed input"
118	              value={claims}
119	              onChange={(_, value) => handleSetClaimsMade(value)}
120	              style={{ maxWidth: '100%' }}
121	            />
122	          </FormGroup>
123	
124	          <FormGroup
125	            fieldId="code-input"
126	            label={t('Code')}
127	            labelIcon={<TooltipInfoButton content={t('tooltipCode')} />}
128	            title=""
129	          >
130	            <TextInput aria-label="code input" value={code} onChange={(_, value) => handleSetCode(value)} />
131	          </FormGroup>
132	
133	          <FormGroup
134	            fieldId="expirationWindow-input"
135	            label={t('Valid for')}
136	            labelIcon={<TooltipInfoButton content={t('tooltipExpirationWindow')} />}
137	            title=""
138	          >
139	            <InputGroup>
140	              <InputGroupItem isFill>
141	                <TextInput
142	                  aria-label="expiration window input"
143	                  value={expiration}
144	                  onChange={(_, value) => handleSetClaimExpiration(value)}
145	                />
146	              </InputGroupItem>
147	              <InputGroupItem style={{ width: '70px' }}>
148	                <FormSelect
149	                  value={timeDimension}
150	                  onChange={(_, value) => onChangeTimeDimension(value as ValidForUnit)}
151	                  aria-label="form valid for select"
152	                >
153	                  {options.map((option, index) => (
154	                    <FormSelectOption key={index} value={option.value} label={option.label} />
155	                  ))}
156	                </FormSelect>
157	              </InputGroupItem>
158	            </InputGroup>
159	          </FormGroup>
160	        </Form>
161	      </StackItem>
162	    </Stack>
163	  );
164	};

